//! API key storage abstracted behind the `SecretStore` trait so a future
//! mobile backend can swap in a different implementation without touching
//! the commands below. The key is never returned to the JS side.

use keyring::Entry;

const SERVICE_NAME: &str = "MySillyTavern";

#[derive(Debug, thiserror::Error)]
pub enum SecretError {
    #[error("keyring error: {0}")]
    Keyring(#[from] keyring::Error),
}

pub trait SecretStore: Send + Sync {
    fn get(&self, connection_id: &str) -> Result<Option<String>, SecretError>;
    fn set(&self, connection_id: &str, key: &str) -> Result<(), SecretError>;
    fn delete(&self, connection_id: &str) -> Result<(), SecretError>;
}

pub struct KeyringStore;

impl KeyringStore {
    fn entry(connection_id: &str) -> Result<Entry, SecretError> {
        Ok(Entry::new(SERVICE_NAME, connection_id)?)
    }
}

impl SecretStore for KeyringStore {
    fn get(&self, connection_id: &str) -> Result<Option<String>, SecretError> {
        let entry = Self::entry(connection_id)?;
        match entry.get_password() {
            Ok(password) => Ok(Some(password)),
            Err(keyring::Error::NoEntry) => Ok(None),
            Err(err) => Err(err.into()),
        }
    }

    fn set(&self, connection_id: &str, key: &str) -> Result<(), SecretError> {
        let entry = Self::entry(connection_id)?;
        entry.set_password(key)?;
        Ok(())
    }

    fn delete(&self, connection_id: &str) -> Result<(), SecretError> {
        let entry = Self::entry(connection_id)?;
        match entry.delete_credential() {
            Ok(()) => Ok(()),
            Err(keyring::Error::NoEntry) => Ok(()),
            Err(err) => Err(err.into()),
        }
    }
}

#[tauri::command]
pub fn set_api_key(connection_id: String, key: String) -> Result<(), String> {
    KeyringStore.set(&connection_id, &key).map_err(|e| e.to_string())
}

#[tauri::command]
pub fn delete_api_key(connection_id: String) -> Result<(), String> {
    KeyringStore.delete(&connection_id).map_err(|e| e.to_string())
}

#[tauri::command]
pub fn has_api_key(connection_id: String) -> Result<bool, String> {
    KeyringStore
        .get(&connection_id)
        .map(|v| v.is_some())
        .map_err(|e| e.to_string())
}

/// Internal helper for other commands (e.g. chat_complete) that need the
/// actual key value. Never exposed as a Tauri command itself.
pub fn get_api_key(connection_id: &str) -> Result<Option<String>, SecretError> {
    KeyringStore.get(connection_id)
}

import Database from "@tauri-apps/plugin-sql";

const DB_URL = "sqlite:mysillytavern.db";

let dbPromise: Promise<Database> | null = null;

/** Lazily opens (and caches) the single SQLite connection for the app. */
export function getDb(): Promise<Database> {
  if (!dbPromise) {
    dbPromise = Database.load(DB_URL);
  }
  return dbPromise;
}

export async function query<T>(sql: string, params: unknown[] = []): Promise<T[]> {
  const db = await getDb();
  return db.select<T[]>(sql, params);
}

export async function execute(sql: string, params: unknown[] = []): Promise<void> {
  const db = await getDb();
  await db.execute(sql, params);
}

export function newId(): string {
  return crypto.randomUUID();
}

export function nowIso(): string {
  return new Date().toISOString();
}

//! Small generic file I/O commands used by frontend features that need to
//! read/write plain text files chosen via a native dialog (World Info JSON
//! import/export for lorebooks — M4). Kept separate from `cards.rs` since
//! it isn't card-specific.

use std::fs;

/// Reads a text file at `path` and returns its contents. Generic
/// counterpart to `read_card_json_file` for non-card text files (e.g.
/// SillyTavern World Info JSON).
#[tauri::command]
pub fn read_text_file(path: String) -> Result<String, String> {
    fs::read_to_string(&path).map_err(|e| format!("nepodařilo se přečíst soubor: {e}"))
}

/// Writes `contents` to a text file at `path`, overwriting it if it exists.
#[tauri::command]
pub fn write_text_file(path: String, contents: String) -> Result<(), String> {
    fs::write(&path, contents).map_err(|e| format!("nepodařilo se uložit soubor: {e}"))
}

use std::collections::HashMap;
use std::sync::Mutex;

use tauri::ipc::Channel;
use tauri::State;
use tokio::sync::mpsc;
use tokio_util::sync::CancellationToken;

use crate::commands::secrets::get_api_key;
use crate::providers::{self, ChatMessage, ConnectionDto, StreamEvent};

/// Tracks in-flight streams by `request_id` so `chat_abort` can cancel
/// them. Managed as Tauri app state.
#[derive(Default)]
pub struct StreamRegistry(Mutex<HashMap<String, CancellationToken>>);

impl StreamRegistry {
    fn insert(&self, request_id: String, token: CancellationToken) {
        self.0.lock().unwrap().insert(request_id, token);
    }

    fn remove(&self, request_id: &str) -> Option<CancellationToken> {
        self.0.lock().unwrap().remove(request_id)
    }
}

/// Non-streamed completion. Used for the "test connection" button in
/// Settings and (later) the memory engine's extractor/summarizer. Shares
/// the same provider code path as `chat_stream`.
#[tauri::command]
pub async fn chat_complete(
    connection: ConnectionDto,
    messages: Vec<ChatMessage>,
) -> Result<String, String> {
    let api_key = get_api_key(&connection.id)
        .map_err(|e| e.to_string())?
        .ok_or_else(|| "Pro toto připojení není uložen žádný API klíč.".to_string())?;

    providers::complete(&connection, &api_key, &messages)
        .await
        .map_err(|e| e.to_string())
}

/// Lists the models offered by a connection's provider, authenticated with
/// the API key stored in the keyring for that connection.
#[tauri::command]
pub async fn list_models(
    connection_id: String,
    provider: String,
    base_url: Option<String>,
) -> Result<Vec<String>, String> {
    let api_key = get_api_key(&connection_id)
        .map_err(|e| e.to_string())?
        .ok_or_else(|| "Pro toto připojení není uložen žádný API klíč.".to_string())?;

    providers::list_models(&provider, base_url.as_deref(), &api_key)
        .await
        .map_err(|e| e.to_string())
}

/// Embeds a batch of texts with the provider's embedding endpoint,
/// authenticated with the connection's keyring key. Returns the embedding
/// model id used plus one vector per text, in order.
#[tauri::command]
pub async fn embed_texts(
    connection_id: String,
    provider: String,
    base_url: Option<String>,
    model: Option<String>,
    texts: Vec<String>,
) -> Result<(String, Vec<Vec<f32>>), String> {
    let api_key = get_api_key(&connection_id)
        .map_err(|e| e.to_string())?
        .ok_or_else(|| "Pro toto připojení není uložen žádný API klíč.".to_string())?;

    providers::embeddings::embed_texts(
        &provider,
        base_url.as_deref(),
        &api_key,
        model.as_deref(),
        &texts,
    )
    .await
    .map_err(|e| e.to_string())
}

/// Streams a chat completion token-by-token over `on_event`. Emits exactly
/// one `Start`, then zero or more `Token`s, then exactly one `Done` or
/// `Error` (unless aborted via `chat_abort`, in which case the stream just
/// stops silently).
#[tauri::command]
pub async fn chat_stream(
    request_id: String,
    connection: ConnectionDto,
    messages: Vec<ChatMessage>,
    on_event: Channel<StreamEvent>,
    registry: State<'_, StreamRegistry>,
) -> Result<(), String> {
    let api_key = match get_api_key(&connection.id) {
        Ok(Some(key)) => key,
        Ok(None) => {
            let _ = on_event.send(StreamEvent::Error {
                message: "Pro toto připojení není uložen žádný API klíč.".to_string(),
                retryable: false,
            });
            return Ok(());
        }
        Err(err) => {
            let _ = on_event.send(StreamEvent::Error {
                message: err.to_string(),
                retryable: false,
            });
            return Ok(());
        }
    };

    let cancel = CancellationToken::new();
    registry.insert(request_id.clone(), cancel.clone());

    let _ = on_event.send(StreamEvent::Start);

    let (tx, mut rx) = mpsc::unbounded_channel::<StreamEvent>();
    let task = tokio::spawn(async move {
        providers::stream_chat(&connection, &api_key, &messages, cancel, tx).await;
    });

    let mut saw_terminal = false;
    while let Some(event) = rx.recv().await {
        let is_terminal = matches!(event, StreamEvent::Done { .. } | StreamEvent::Error { .. });
        let _ = on_event.send(event);
        if is_terminal {
            saw_terminal = true;
            break;
        }
    }

    let _ = task.await;
    // If `chat_abort` already removed the registry entry, this stream was
    // cancelled deliberately — the frontend already knows and doesn't need
    // a synthetic error. Otherwise, if we never saw a terminal event, the
    // stream ended abnormally (bug in a provider adapter) and the frontend
    // would otherwise spin forever waiting for one.
    let was_aborted = registry.remove(&request_id).is_none();
    if !saw_terminal && !was_aborted {
        let _ = on_event.send(StreamEvent::Error {
            message: "Stream skončil bez odpovědi.".to_string(),
            retryable: true,
        });
    }

    Ok(())
}

/// Cancels a running `chat_stream` by request id. No-op if it already
/// finished or never existed.
#[tauri::command]
pub fn chat_abort(request_id: String, registry: State<'_, StreamRegistry>) -> Result<(), String> {
    if let Some(token) = registry.remove(&request_id) {
        token.cancel();
    }
    Ok(())
}

//! Character card import/export commands. Reads/writes the embedded PNG
//! metadata via `png_card` and manages the on-disk copies of card avatars
//! kept under `<app_data_dir>/avatars/`.

use std::fs;
use std::path::PathBuf;

use serde::Serialize;
use tauri::{AppHandle, Manager};

use crate::png_card;

fn avatars_dir(app: &AppHandle) -> Result<PathBuf, String> {
    let base = app
        .path()
        .app_data_dir()
        .map_err(|e| format!("nepodařilo se najít adresář aplikace: {e}"))?;
    let dir = base.join("avatars");
    fs::create_dir_all(&dir).map_err(|e| format!("nepodařilo se vytvořit adresář avatarů: {e}"))?;
    Ok(dir)
}

#[derive(Debug, Serialize)]
pub struct ImportCardResult {
    pub card_json: String,
    pub avatar_saved_to: String,
}

/// Reads a character card from a PNG file at `path` (any location the user
/// picked via a file dialog) and stores a copy of that PNG under the app's
/// avatars directory, named by a freshly generated id — independent of
/// whatever character id the frontend later assigns the imported card.
#[tauri::command]
pub fn import_card_png(app: AppHandle, path: String) -> Result<ImportCardResult, String> {
    let bytes = fs::read(&path).map_err(|e| format!("nepodařilo se přečíst soubor: {e}"))?;
    let card_json = png_card::read_card_json(&bytes).map_err(|e| e.to_string())?;

    let dir = avatars_dir(&app)?;
    let filename = format!("{}.png", uuid::Uuid::new_v4());
    let dest = dir.join(&filename);
    fs::write(&dest, &bytes).map_err(|e| format!("nepodařilo se uložit avatar: {e}"))?;

    Ok(ImportCardResult {
        card_json,
        avatar_saved_to: dest.to_string_lossy().to_string(),
    })
}

/// Reads a plain (non-PNG) JSON card file and returns its raw text. Used by
/// `cardImport.ts` for JSON-only card imports (no avatar image involved).
#[tauri::command]
pub fn read_card_json_file(path: String) -> Result<String, String> {
    fs::read_to_string(&path).map_err(|e| format!("nepodařilo se přečíst soubor: {e}"))
}

/// Merges `card_json` into the PNG at `avatar_path` and writes the result
/// to `out_path`. Used for "export character to PNG".
#[tauri::command]
pub fn export_card_png(card_json: String, avatar_path: String, out_path: String) -> Result<(), String> {
    let bytes = fs::read(&avatar_path).map_err(|e| format!("nepodařilo se přečíst avatar: {e}"))?;
    let with_card = png_card::write_card_json(&bytes, &card_json).map_err(|e| e.to_string())?;
    fs::write(&out_path, with_card).map_err(|e| format!("nepodařilo se uložit soubor: {e}"))?;
    Ok(())
}

/// Ensures a placeholder avatar PNG exists under the app data directory and
/// returns its path. Used as the source image for exporting/creating
/// characters that were imported from plain JSON (no original PNG) or
/// created from scratch in the editor.
#[tauri::command]
pub fn ensure_placeholder_avatar(app: AppHandle) -> Result<String, String> {
    let dir = avatars_dir(&app)?;
    let dest = dir.join("_placeholder.png");
    if !dest.exists() {
        fs::write(&dest, png_card::placeholder_png())
            .map_err(|e| format!("nepodařilo se uložit výchozí avatar: {e}"))?;
    }
    Ok(dest.to_string_lossy().to_string())
}

