/**
 * Auto-illustration background queue — generates images for locked facts
 * and inventory items using the `generate_illustration` Tauri command.
 *
 * Design:
 * - In-memory FIFO queue (no persistence — items regenerate on restart).
 * - Processes one item at a time to respect rate limits.
 * - Checks `image_gen_enabled` setting before every generation.
 * - Obtains the connection from `image_gen_connection_id` setting, with
 *   a fallback to the first connection that has `purposes` including "image".
 * - After generation, persists the returned file path to the DB.
 */

import { invoke } from "@tauri-apps/api/core";
import { getSetting } from "../db/repositories/settingsRepo";
import { setFactImagePath } from "../db/repositories/ledgerRepo";
import { setInventoryItemImagePath } from "../db/repositories/personasRepo";
import { listConnections } from "../db/repositories/connectionsRepo";

interface QueueItem {
  targetType: "inventory" | "fact";
  targetId: string;
  /** For inventory items: the persona id */
  personaId?: string;
  /** For inventory items: index in the inventory array */
  itemIndex?: number;
  prompt: string;
}

const queue: QueueItem[] = [];
let processing = false;

/**
 * Enqueues an illustration generation request. Fire-and-forget — callers
 * should never await this; it returns immediately after queuing.
 */
export function enqueueIllustration(
  targetType: "inventory" | "fact",
  targetId: string,
  prompt: string,
  extra?: { personaId?: string; itemIndex?: number },
): void {
  queue.push({ targetType, targetId, prompt, ...extra });
  if (!processing) {
    processQueue();
  }
}

async function processQueue(): Promise<void> {
  if (processing) return;
  processing = true;

  while (queue.length > 0) {
    const item = queue.shift()!;
    try {
      // Check if generation is enabled
      const enabled = await getSetting("image_gen_enabled");
      if (enabled !== "true" && enabled !== "1") {
        continue;
      }

      // Resolve connection: prefer explicit image_gen_connection_id,
      // otherwise find first connection with "image" purpose
      const connectionId = await resolveImageConnection();

      const imagePath: string = await invoke("generate_illustration", {
        connectionId: connectionId ?? null,
        prompt: item.prompt,
      });

      // Persist the result
      if (item.targetType === "fact") {
        await setFactImagePath(item.targetId, imagePath);
      } else if (
        item.targetType === "inventory" &&
        item.personaId !== undefined &&
        item.itemIndex !== undefined
      ) {
        await setInventoryItemImagePath(item.personaId, item.itemIndex, imagePath);
      }

      // Respect rate limit: small delay between generations
      const limitStr = await getSetting("image_gen_limit");
      const delayMs = parseDelay(limitStr);
      if (delayMs > 0 && queue.length > 0) {
        await sleep(delayMs);
      }
    } catch (err) {
      console.warn("imageGenQueue: generation failed for", item.targetType, item.targetId, err);
      // Continue with next item — don't block the queue on one failure
    }
  }

  processing = false;
}

/** Resolves the connection id to use for image generation. */
async function resolveImageConnection(): Promise<string | null> {
  const explicit = await getSetting("image_gen_connection_id");
  if (explicit) return explicit;

  // Fallback: first connection with "image" in its purposes
  const connections = await listConnections();
  for (const conn of connections) {
    // Check if the connection has purposes that include "image"
    // (purposes is a future field; for now just return the first connection)
    const purposesRaw = await getSetting(`connection_purposes_${conn.id}`);
    if (purposesRaw) {
      try {
        const purposes: string[] = JSON.parse(purposesRaw);
        if (purposes.includes("image")) return conn.id;
      } catch {
        // ignore parse errors
      }
    }
  }
  // Ultimate fallback: first available connection
  return connections.length > 0 ? connections[0].id : null;
}

function parseDelay(raw: string | null): number {
  if (!raw) return 2000; // default 2s delay
  const ms = Number(raw);
  return Number.isFinite(ms) && ms > 0 ? ms : 2000;
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

