/**
 * Auto-illustration background queue — generates images for locked facts
 * and inventory items using the `generate_illustration` Tauri command.
 *
 * Design:
 * - In-memory FIFO queue (no persistence — items regenerate on restart).
 * - Processes one item at a time to respect rate limits.
 * - Checks `image_gen_enabled` setting before every generation.
 * - Obtains the connection from `image_gen_connection_id` setting, with
 *   a fallback to the first connection that has `purposes` including "image".
 * - After generation, persists the returned file path to the DB.
 */

import { invoke } from "@tauri-apps/api/core";
import { getSetting } from "../db/repositories/settingsRepo";
import { execute, nowIso, query } from "../db/database";
import { listConnections } from "../db/repositories/connectionsRepo";

interface QueueItem {
  targetType: "inventory" | "fact";
  targetId: string;
  /** For inventory items: the persona id */
  personaId?: string;
  /** For inventory items: index in the inventory array */
  itemIndex?: number;
  prompt: string;
}

const queue: QueueItem[] = [];
let processing = false;

/**
 * Enqueues an illustration generation request. Fire-and-forget — callers
 * should never await this; it returns immediately after queuing.
 */
export function enqueueIllustration(
  targetType: "inventory" | "fact",
  targetId: string,
  prompt: string,
  extra?: { personaId?: string; itemIndex?: number },
): void {
  queue.push({ targetType, targetId, prompt, ...extra });
  if (!processing) {
    processQueue();
  }
}

async function processQueue(): Promise<void> {
  if (processing) return;
  processing = true;

  while (queue.length > 0) {
    const item = queue.shift()!;
    try {
      // Check if generation is enabled
      const enabled = await getSetting("image_gen_enabled");
      if (enabled !== "true" && enabled !== "1") {
        continue;
      }

      // Resolve connection: prefer explicit image_gen_connection_id,
      // otherwise find first connection with "image" purpose
      const connectionId = await resolveImageConnection();

      const imagePath: string = await invoke("generate_illustration", {
        connectionId: connectionId ?? null,
        prompt: item.prompt,
      });

      // Persist the result
      if (item.targetType === "fact") {
        await execute(
          "UPDATE ledger_facts SET image_path = $1, updated_at = $2 WHERE id = $3",
          [imagePath, nowIso(), item.targetId],
        );
      } else if (
        item.targetType === "inventory" &&
        item.personaId !== undefined &&
        item.itemIndex !== undefined
      ) {
        // Update the inventory JSON directly
        const rows = await query<{ inventory: string }>(
          "SELECT inventory FROM personas WHERE id = $1",
          [item.personaId],
        );
        if (rows[0]) {
          const inventory = JSON.parse(rows[0].inventory || "[]");
          if (item.itemIndex >= 0 && item.itemIndex < inventory.length) {
            inventory[item.itemIndex].image_path = imagePath;
            await execute(
              "UPDATE personas SET inventory = $1, updated_at = $2 WHERE id = $3",
              [JSON.stringify(inventory), nowIso(), item.personaId],
            );
          }
        }
      }

      // Respect rate limit: small delay between generations
      const limitStr = await getSetting("image_gen_limit");
      const delayMs = parseDelay(limitStr);
      if (delayMs > 0 && queue.length > 0) {
        await sleep(delayMs);
      }
    } catch (err) {
      console.warn("imageGenQueue: generation failed for", item.targetType, item.targetId, err);
      // Continue with next item — don't block the queue on one failure
    }
  }

  processing = false;
}

/** Resolves the connection id to use for image generation. */
async function resolveImageConnection(): Promise<string | null> {
  const explicit = await getSetting("image_gen_connection_id");
  if (explicit) return explicit;

  // Fallback: first connection with "image" in its purposes
  const connections = await listConnections();
  for (const conn of connections) {
    // Check if the connection has purposes that include "image"
    // (purposes is a future field; for now just return the first connection)
    const purposesRaw = await getSetting(`connection_purposes_${conn.id}`);
    if (purposesRaw) {
      try {
        const purposes: string[] = JSON.parse(purposesRaw);
        if (purposes.includes("image")) return conn.id;
      } catch {
        // ignore parse errors
      }
    }
  }
  // Ultimate fallback: first available connection
  return connections.length > 0 ? connections[0].id : null;
}

function parseDelay(raw: string | null): number {
  if (!raw) return 2000; // default 2s delay
  const ms = Number(raw);
  return Number.isFinite(ms) && ms > 0 ? ms : 2000;
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

import { execute, newId, nowIso, query } from "../database";
import { enqueueIllustration } from "../../memory/imageGenQueue";

export interface InventoryEntry {
  item: string;
  qty: number;
  note: string;
  image_path?: string;
}

export interface Persona {
  id: string;
  name: string;
  description: string;
  avatarPath: string | null;
  isDefault: boolean;
  inventory: InventoryEntry[];
  createdAt: string;
  updatedAt: string;
}

export interface PersonaDraft {
  name: string;
  description: string;
  avatarPath: string | null;
}

interface PersonaRow {
  id: string;
  name: string;
  description: string;
  avatar_path: string | null;
  is_default: number;
  inventory: string;
  created_at: string;
  updated_at: string;
}

function parseInventory(raw: string): InventoryEntry[] {
  try {
    return JSON.parse(raw);
  } catch {
    return [];
  }
}

function toPersona(row: PersonaRow): Persona {
  return {
    id: row.id,
    name: row.name,
    description: row.description,
    avatarPath: row.avatar_path,
    isDefault: row.is_default === 1,
    inventory: parseInventory(row.inventory),
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

export async function listPersonas(): Promise<Persona[]> {
  const rows = await query<PersonaRow>("SELECT * FROM personas ORDER BY name ASC", []);
  return rows.map(toPersona);
}

export async function getPersona(id: string): Promise<Persona | null> {
  const rows = await query<PersonaRow>("SELECT * FROM personas WHERE id = $1", [id]);
  return rows[0] ? toPersona(rows[0]) : null;
}

export async function getDefaultPersona(): Promise<Persona | null> {
  const rows = await query<PersonaRow>(
    "SELECT * FROM personas WHERE is_default = 1 LIMIT 1",
    [],
  );
  return rows[0] ? toPersona(rows[0]) : null;
}

export async function createPersona(draft: PersonaDraft): Promise<Persona> {
  const id = newId();
  const now = nowIso();
  // First persona ever created becomes the default automatically, so a
  // fresh install always has a usable default without extra user action.
  const existing = await query<{ n: number }>("SELECT COUNT(*) as n FROM personas", []);
  const isDefault = (existing[0]?.n ?? 0) === 0;
  await execute(
    `INSERT INTO personas (id, name, description, avatar_path, is_default, inventory, created_at, updated_at)
     VALUES ($1, $2, $3, $4, $5, '[]', $6, $6)`,
    [id, draft.name, draft.description, draft.avatarPath, isDefault ? 1 : 0, now],
  );
  return {
    id,
    name: draft.name,
    description: draft.description,
    avatarPath: draft.avatarPath,
    isDefault,
    inventory: [],
    createdAt: now,
    updatedAt: now,
  };
}

export interface PersonaUpdate {
  name: string;
  description: string;
}

export async function updatePersona(id: string, patch: PersonaUpdate): Promise<void> {
  await execute(
    `UPDATE personas SET name = $2, description = $3, updated_at = $4 WHERE id = $1`,
    [id, patch.name, patch.description, nowIso()],
  );
}

export async function updatePersonaAvatar(id: string, avatarPath: string | null): Promise<void> {
  await execute("UPDATE personas SET avatar_path = $2, updated_at = $3 WHERE id = $1", [
    id,
    avatarPath,
    nowIso(),
  ]);
}

/** Sets `id` as the default persona, clearing the flag on every other
 * persona — only one persona may be default at a time. */
export async function setDefaultPersona(id: string): Promise<void> {
  const now = nowIso();
  await execute(`UPDATE personas SET is_default = 0, updated_at = $2 WHERE id != $1`, [id, now]);
  await execute(`UPDATE personas SET is_default = 1, updated_at = $2 WHERE id = $1`, [id, now]);
}

export async function deletePersona(id: string): Promise<void> {
  await execute("DELETE FROM personas WHERE id = $1", [id]);
}

// ---- inventory helpers ------------------------------------------------

export async function getPersonaInventory(personaId: string): Promise<InventoryEntry[]> {
  const rows = await query<{ inventory: string }>(
    "SELECT inventory FROM personas WHERE id = $1",
    [personaId],
  );
  return rows[0] ? parseInventory(rows[0].inventory) : [];
}

export async function updatePersonaInventory(
  personaId: string,
  inventory: InventoryEntry[],
): Promise<void> {
  await execute(
    "UPDATE personas SET inventory = $2, updated_at = $3 WHERE id = $1",
    [personaId, JSON.stringify(inventory), nowIso()],
  );

  // Enqueue illustrations for items that don't have one yet (fire-and-forget)
  for (let i = 0; i < inventory.length; i++) {
    const entry = inventory[i];
    if (!entry.image_path && entry.item) {
      enqueueIllustration("inventory", personaId, entry.item, {
        personaId,
        itemIndex: i,
      });
    }
  }
}

export async function setInventoryItemImagePath(
  personaId: string,
  itemIndex: number,
  imagePath: string | null,
): Promise<void> {
  const inventory = await getPersonaInventory(personaId);
  if (itemIndex < 0 || itemIndex >= inventory.length) return;
  inventory[itemIndex].image_path = imagePath ?? undefined;
  await updatePersonaInventory(personaId, inventory);
}

import { create } from "zustand";

import {
  createPersona,
  deletePersona,
  listPersonas,
  setDefaultPersona,
  updatePersona,
  updatePersonaAvatar,
  updatePersonaInventory,
  setInventoryItemImagePath,
  type Persona,
  type PersonaDraft,
  type PersonaUpdate,
  type InventoryEntry,
} from "../db/repositories/personasRepo";

interface PersonasState {
  personas: Persona[];
  loaded: boolean;
  load: () => Promise<void>;
  reload: () => Promise<void>;
  create: (draft: PersonaDraft) => Promise<Persona>;
  update: (id: string, patch: PersonaUpdate) => Promise<void>;
  setAvatar: (id: string, avatarPath: string | null) => Promise<void>;
  setDefault: (id: string) => Promise<void>;
  remove: (id: string) => Promise<void>;
  updateInventory: (personaId: string, inventory: InventoryEntry[]) => Promise<void>;
  setItemImage: (personaId: string, itemIndex: number, imagePath: string | null) => Promise<void>;
}

export const usePersonasStore = create<PersonasState>((set, get) => ({
  personas: [],
  loaded: false,

  load: async () => {
    if (get().loaded) return;
    await get().reload();
  },

  reload: async () => {
    const personas = await listPersonas();
    set({ personas, loaded: true });
  },

  create: async (draft) => {
    const persona = await createPersona(draft);
    await get().reload();
    return persona;
  },

  update: async (id, patch) => {
    await updatePersona(id, patch);
    set({
      personas: get().personas.map((p) => (p.id === id ? { ...p, ...patch } : p)),
    });
  },

  setAvatar: async (id, avatarPath) => {
    await updatePersonaAvatar(id, avatarPath);
    set({ personas: get().personas.map((p) => (p.id === id ? { ...p, avatarPath } : p)) });
  },

  setDefault: async (id) => {
    await setDefaultPersona(id);
    set({
      personas: get().personas.map((p) => ({ ...p, isDefault: p.id === id })),
    });
  },

  remove: async (id) => {
    await deletePersona(id);
    set({ personas: get().personas.filter((p) => p.id !== id) });
  },

  updateInventory: async (personaId, inventory) => {
    await updatePersonaInventory(personaId, inventory);
    set({
      personas: get().personas.map((p) =>
        p.id === personaId ? { ...p, inventory } : p,
      ),
    });
  },

  setItemImage: async (personaId, itemIndex, imagePath) => {
    await setInventoryItemImagePath(personaId, itemIndex, imagePath);
    set({
      personas: get().personas.map((p) => {
        if (p.id !== personaId) return p;
        const inventory = [...p.inventory];
        if (itemIndex >= 0 && itemIndex < inventory.length) {
          inventory[itemIndex] = { ...inventory[itemIndex], image_path: imagePath ?? undefined };
        }
        return { ...p, inventory };
      }),
    });
  },
}));

