/**
 * Updates only the inventory array for a persona. Detects newly added items
 * without images and enqueues them for auto-illustration.
 */
export async function updatePersonaInventory(
  personaId: string,
  inventory: InventoryEntry[],
): Promise<void> {
  const current = await getPersona(personaId);
  const oldNames = current
    ? new Set(current.inventory.map((i) => i.item.toLowerCase()))
    : new Set<string>();

  await execute(
    `UPDATE personas SET inventory = $2, updated_at = $3 WHERE id = $1`,
    [personaId, JSON.stringify(inventory), nowIso()],
  );

  // Enqueue illustration for newly added items that don't already have an image.
  for (const entry of inventory) {
    if (!oldNames.has(entry.item.toLowerCase()) && !entry.image_path) {
      const { enqueueIllustration } = await import("../../memory/imageGenQueue");
      enqueueIllustration(
        "inventory",
        personaId,
        `Fantasy RPG item: ${entry.item}`,
        entry.item,
      );
    }
  }
}

/**
 * Sets the `image_path` on a specific inventory item within a persona's
 * inventory JSON array.
 */
export async function setInventoryItemImage(
  personaId: string,
  itemName: string,
  imagePath: string,
): Promise<void> {
  const persona = await getPersona(personaId);
  if (!persona) return;

  const inventory = persona.inventory.map((entry) =>
    entry.item.toLowerCase() === itemName.toLowerCase()
      ? { ...entry, image_path: imagePath }
      : entry,
  );

  await execute(
    `UPDATE personas SET inventory = $2, updated_at = $3 WHERE id = $1`,
    [personaId, JSON.stringify(inventory), nowIso()],
  );
}

